using System.Threading.Channels;

/// <summary>
/// .NET 8 migration of BackgroundProcessor.
///
/// Key breaking changes addressed:
///   1. Thread.Abort() throws PlatformNotSupportedException in .NET 8.
///   2. ThreadAbortException / Thread.ResetAbort() no longer exist.
///   3. Raw Thread + volatile bool replaced with CancellationToken
///      for cooperative cancellation that unblocks waiting calls.
///   4. Blocking GetNextItem() migrated to async with cancellation support.
/// </summary>
public class BackgroundProcessor : IAsyncDisposable
{
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        _workerTask = Task.Run(() => ProcessLoopAsync(_cts.Token));
    }

    private async Task ProcessLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                // Pass the token so blocking calls can be interrupted
                // without Thread.Abort().
                var item = await GetNextItemAsync(ct);
                await ProcessItemAsync(item, ct);
            }
            catch (OperationCanceledException) when (ct.IsCancellationRequested)
            {
                // Graceful shutdown requested — replaces ThreadAbortException handler.
                // Unlike Thread.Abort(), this does NOT interrupt finally blocks
                // or leave objects in a torn state.
                await RollbackCurrentTransactionAsync();
                break; // exit the loop cleanly; finally still runs
            }
            finally
            {
                await FlushBuffersAsync();
            }
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        timeout ??= TimeSpan.FromSeconds(2);

        // Signal cancellation — unblocks any awaiting call immediately.
        await _cts.CancelAsync();  // .NET 8+; use _cts.Cancel() on older TFMs

        if (_workerTask is not null)
        {
            // Wait for the worker to finish, but don't wait forever.
            using var timeoutCts = new CancellationTokenSource(timeout.Value);
            try
            {
                await _workerTask.WaitAsync(timeoutCts.Token);
            }
            catch (TimeoutException)
            {
                // Worker didn't stop in time — log/alert but never
                // Thread.Abort(). The token is already signaled so
                // the next cancellation-aware call will exit.
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopAsync();
        _cts.Dispose();
    }

    // --- Stubs for illustration ---
    private Task<object> GetNextItemAsync(CancellationToken ct) => Task.FromResult<object>(new());
    private Task ProcessItemAsync(object item, CancellationToken ct) => Task.CompletedTask;
    private Task RollbackCurrentTransactionAsync() => Task.CompletedTask;
    private Task FlushBuffersAsync() => Task.CompletedTask;
}

